package com.sso.saml.config;

import com.sso.saml.security.SamlAuthenticationFilter;
import com.sso.saml.security.SamlAuthenticationProvider;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.config.annotation.authentication.builders.AuthenticationManagerBuilder;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Autowired
    private SamlAuthenticationProvider samlAuthenticationProvider;

    @Bean
    public AuthenticationManager authenticationManager(HttpSecurity http) throws Exception {
        AuthenticationManagerBuilder authBuilder =
                http.getSharedObject(AuthenticationManagerBuilder.class);
        authBuilder.authenticationProvider(samlAuthenticationProvider);
        return authBuilder.build();
    }

    @Bean
    public SamlAuthenticationFilter samlAuthenticationFilter(AuthenticationManager authenticationManager) {
        SamlAuthenticationFilter filter = new SamlAuthenticationFilter("/saml/acs");
        filter.setAuthenticationManager(authenticationManager);
        return filter;
    }

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http,
                                            SamlAuthenticationFilter samlAuthenticationFilter) throws Exception {
        http
            .csrf(csrf -> csrf
                .ignoringRequestMatchers("/saml/**")
            )
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/saml/**", "/saml/metadata", "/saml/login", "/login", "/error").permitAll()
                .requestMatchers("/dashboard/**", "/api/**").authenticated()
                .anyRequest().authenticated()
            )
            .addFilterBefore(samlAuthenticationFilter, UsernamePasswordAuthenticationFilter.class)
            .exceptionHandling(ex -> ex
                .authenticationEntryPoint((request, response, authException) -> {
                    response.sendRedirect("/saml/login");
                })
            )
            .logout(logout -> logout
                .logoutUrl("/saml/logout")
                .logoutSuccessUrl("/login?logout")
                .invalidateHttpSession(true)
                .deleteCookies("JSESSIONID")
            );

        return http.build();
    }
}

