package com.sso.saml.credential;

import com.sso.saml.config.SamlProperties;
import org.opensaml.security.credential.Credential;
import org.opensaml.security.x509.BasicX509Credential;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.core.io.ClassPathResource;
import org.springframework.stereotype.Component;

import javax.annotation.PostConstruct;
import java.io.FileInputStream;
import java.io.InputStream;
import java.security.KeyStore;
import java.security.PrivateKey;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;

@Component
public class KeyStoreCredentialManager {

    @Autowired
    private SamlProperties samlProperties;

    private Credential spCredential;
    private X509Certificate idpCertificate;

    @PostConstruct
    public void init() throws Exception {
        loadSpCredential();
        loadIdpCertificate();
    }

    private void loadSpCredential() throws Exception {
        KeyStore keyStore = KeyStore.getInstance("JKS");
        try (InputStream is = new ClassPathResource(samlProperties.getKeystorePath()).getInputStream()) {
            keyStore.load(is, samlProperties.getKeystorePassword().toCharArray());
        }

        PrivateKey privateKey = (PrivateKey) keyStore.getKey(
                samlProperties.getKeyAlias(),
                samlProperties.getKeyPassword().toCharArray()
        );

        X509Certificate certificate = (X509Certificate) keyStore.getCertificate(samlProperties.getKeyAlias());

        BasicX509Credential credential = new BasicX509Credential(certificate, privateKey);
        credential.setEntityId(samlProperties.getEntityId());
        this.spCredential = credential;
    }

    private void loadIdpCertificate() throws Exception {
        CertificateFactory cf = CertificateFactory.getInstance("X.509");
        try (InputStream is = new ClassPathResource(samlProperties.getIdp().getCertificatePath()).getInputStream()) {
            this.idpCertificate = (X509Certificate) cf.generateCertificate(is);
        }
    }

    public Credential getSpCredential() {
        return spCredential;
    }

    public X509Certificate getSpCertificate() {
        return ((BasicX509Credential) spCredential).getEntityCertificate();
    }

    public X509Certificate getIdpCertificate() {
        return idpCertificate;
    }

    public Credential getIdpCredential() {
        return new BasicX509Credential(idpCertificate);
    }
}

